choose.when:
SELECT COALESCE( (SELECT id FROM moondap.balance_questions WHERE id > #{id}
ORDER BY id ASC LIMIT 1), (SELECT id FROM moondap.balance_questions
ORDER BY id ASC LIMIT 1) )

choose.otherwise:
SELECT COALESCE( (SELECT id FROM moondap.balance_questions WHERE id < #{id}
ORDER BY id DESC LIMIT 1), (SELECT id FROM moondap.balance_questions
ORDER BY id DESC LIMIT 1) )

